  /** Tính tổng số khách (người lớn + trẻ em) trong một yêu cầu phòng */
  private getGuestCount(room: HotelSearchRoomDto) {
    return (room.adults || 0) + (room.children?.length || 0);
  }

  /**
   * Phân tích các ngày lưu trú để xác định có đêm nào rơi vào weekend/weekday
   */
  private analyzeStayDays(checkIn: dayjs.Dayjs, checkOut: dayjs.Dayjs) {
    let hasWeekendNights = false;
    let hasWeekdayNights = false;

    let current = checkIn;
    while (current.isBefore(checkOut)) {
      const dayOfWeek = current.day(); // 0 = Sunday, 1 = Monday, ..., 6 = Saturday
      if (dayOfWeek === 0 || dayOfWeek === 5 || dayOfWeek === 6) {
        // Friday, Saturday, Sunday
        hasWeekendNights = true;
      } else {
        hasWeekdayNights = true;
      }
      current = current.add(1, 'day');
    }

    return { hasWeekendNights, hasWeekdayNights };
  }

  /**
   * Áp dụng khuyến mãi cho tất cả options dựa trên các tiêu chí:
   * - roomId: Khuyến mãi theo loại phòng cụ thể
   * - stayNights: Min/Max nights
   * - daysUntilCheckIn: Early Bird (advance purchase) / Last Minute
   * - hasWeekendNights: Weekend deals
   * - hasWeekdayNights: Weekday deals
   */
  private applyPromotionsToOptions(
    options: HotelPriceOption[],
    promotions: RatePromotion[],
    conditions: {
      stayNights: number;
      daysUntilCheckIn: number;
      hasWeekendNights: boolean;
      hasWeekdayNights: boolean;
    },
  ): HotelPriceOption[] {
    return options.map(option => {
      // Step 3: Kiểm tra điều kiện hợp lệ - Lọc khuyến mãi áp dụng cho option này
      const applicablePromotions = this.ratePromotionRepo.filterByConditions(promotions, {
        roomId: option.roomId, // Kiểm tra promotion cho phòng cụ thể
        stayNights: conditions.stayNights, // Kiểm tra min/max nights
        daysUntilCheckIn: conditions.daysUntilCheckIn, // Early Bird / Last Minute
        hasWeekendNights: conditions.hasWeekendNights, // Weekend deals
        hasWeekdayNights: conditions.hasWeekdayNights, // Weekday deals
      });

      // Không có promotion hợp lệ → trả về option gốc
      if (!applicablePromotions.length) {
        return option;
      }

      // Step 4: Tính giá đã áp dụng khuyến mãi (chọn promotion tốt nhất)
      const promoResult = this.applyPromotionsToOption(option.baseTotal, conditions.stayNights, applicablePromotions);

      return {
        ...option,
        discountTotal: promoResult.discountTotal,
        netTotal: promoResult.totalAfterPromo,
        appliedPromotions: promoResult.appliedPromotions,
      };
    });
  }

  /**
   * Áp dụng khuyến mãi cho một option cụ thể
   */
  private applyPromotionsToOption(
    baseTotal: number,
    stayNights: number,
    promotions: RatePromotion[],
  ): {
    discountTotal: number;
    totalAfterPromo: number;
    appliedPromotions: AppliedPromotionDto[];
  } {
    if (!promotions.length) {
      return { discountTotal: 0, totalAfterPromo: baseTotal, appliedPromotions: [] };
    }

    // Sắp xếp theo priority (cao nhất trước), sau đó theo discount (lớn nhất trước)
    const sorted = [...promotions].sort((a, b) => {
      if (b.priority !== a.priority) return b.priority - a.priority;
      const discountA = this.calculateDiscount(baseTotal, stayNights, a);
      const discountB = this.calculateDiscount(baseTotal, stayNights, b);
      return discountB - discountA;
    });

    // Lấy khuyến mãi tốt nhất
    const bestPromo = sorted[0];
    const discount = this.calculateDiscount(baseTotal, stayNights, bestPromo);
    const totalAfterPromo = Math.max(0, baseTotal - discount);

    const appliedPromotions: AppliedPromotionDto[] = [
      {
        promotionId: bestPromo.id,
        promotionName: bestPromo.name,
        promotionType: bestPromo.promoType,
        discountAmount: discount,
        displayText: this.buildPromotionDisplayText(bestPromo, discount, stayNights),
        valueAddDescription: bestPromo.valueAddDescription,
      },
    ];

    return { discountTotal: discount, totalAfterPromo, appliedPromotions };
  }

  private buildPromotionDisplayText(promo: RatePromotion, discount: number, stayNights: number): string {
    switch (promo.promoType) {
      case RatePromotionType.PERCENT:
        return `Ưu đãi ${promo.value}%`;
      case RatePromotionType.FIXED:
        return `Giảm ${discount.toLocaleString('vi-VN')} VNĐ`;
      case RatePromotionType.STAY_PAY: {
        const payNights = Math.max(1, Number(promo.value));
        const freeNights = Math.floor(stayNights / (payNights + 1));
        return freeNights > 0 ? `Miễn phí ${freeNights} đêm` : 'Khuyến mãi Stay & Pay';
      }
      case RatePromotionType.VALUE_ADD:
        return promo.valueAddDescription || 'Ưu đãi thêm dịch vụ';
      case RatePromotionType.NEW_PRICE:
        return `Giá ưu đãi ${Number(promo.value).toLocaleString('vi-VN')} VNĐ`;
      default:
        return 'Khuyến mãi đặc biệt';
    }
  }
}

