  ) {}

  private getNameRatePlan(
    condition: CancellationType,
    mealPlan: MealPlan | null,
    roomName: string,
    amount?: number,
    unitType?: UnitType,
  ) {
    const nameConditionMap = {
      [CancellationType.NO_CANCELLATION]: 'NR',
      [CancellationType.FREE_CANCELLATION]: 'Free Cancel',
      [CancellationType.CANCELLATION_CHARGE]: `${amount}${unitType === UnitType.PERCENTAGE ? '%' : 'VND'} Refund`,
    };
    return [roomName, mealPlan, nameConditionMap[condition]].filter(Boolean).join(' - ');
  }

  async getPropertyContent(params: GetPropertyContentReq): Promise<GetPropertyContentRes> {
    const response = await myTour.get<GetPropertyContentRes>('/api-partner/hotel-content/properties/content', {
      params,
    });
    const data = response.data;

    if (data?.code !== StatusCodes.OK || !data?.data) return data;

    const items: GetPropertyContentItem[] = data.data.items || [];
    if (items.length === 0) return data;

    const hotelCodes: string[] = items.map(item => `H${item.id}`);
    const existingHotels: (Hotel | null)[] = await Promise.all(
      hotelCodes.map(code => this.hotelService.checkExistByCode(code)),
    );

    const allAmenityKeys = new Set<string>();
    items.forEach(item => {
      const groupAmenities: MyTourAmenity[] = item?.groupAmenities?.flatMap(ga => ga.amenities) || [];
      groupAmenities.forEach(ga => {
        if (ga.name) allAmenityKeys.add(generateCategoryKey(ga.name));
      });

      item?.rooms?.forEach(room => {
        const groupRoomAmenities: MyTourAmenity[] = room?.groupAmenities?.flatMap(ga => ga.amenities) || [];
        groupRoomAmenities.forEach(gra => {
          if (gra.name) allAmenityKeys.add(generateCategoryKey(gra.name));
        });
      });
    });

    const amenityKeysArray: string[] = Array.from(allAmenityKeys);
    const existingAmenities: Amenity[] =
      amenityKeysArray.length > 0 ? await this.amenityRepo.find({ where: amenityKeysArray.map(key => ({ key })) }) : [];
    const amenityMap = new Map<string, Amenity>(existingAmenities.map(a => [a.key, a]));

    // Start transaction
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    await queryRunner.startTransaction();

    try {
      for (let i = 0; i < items.length; i++) {
        const item = items[i];
        const existHotel = existingHotels[i];

        if (!existHotel) {
          const createFiles = (images: Image[], thumbnailUrl: string, name: string): File[] => {
            const files: File[] = (images || []).map(image => {
              const file = new File();
              file.name = name;
              file.fileUrl = image.origin;
              file.status = FileStatus.ATTACHED;
              file.storageKey = '';
              file.path = image.origin;
              file.ownerId = 'AIRDATA';
              file.createdBy = 'AIRDATA';
              file.updatedBy = 'AIRDATA';
              return file;
            });

            if (thumbnailUrl) {
              const thumbnailFile = new File();
              thumbnailFile.name = name;
              thumbnailFile.fileUrl = thumbnailUrl;
              thumbnailFile.storageKey = '';
              thumbnailFile.path = thumbnailUrl;
              thumbnailFile.status = FileStatus.ATTACHED;
              thumbnailFile.ownerId = 'AIRDATA';
              thumbnailFile.createdBy = 'AIRDATA';
              thumbnailFile.updatedBy = 'AIRDATA';
              files.push(thumbnailFile);
            }

            return files;
          };

          // Create or get amenities helper
          const getOrCreateAmenities = async (
            amenityData: MyTourAmenity[],
            type: AmenityType,
            iconFallback?: string,
          ): Promise<Amenity[]> => {
            const amenitiesToCreate: Amenity[] = [];
            const amenityResults: Amenity[] = [];

            amenityData.forEach(amenityItem => {
              if (!amenityItem.name) return;

              const key = generateCategoryKey(amenityItem.name);
              const existing = amenityMap.get(key);

              if (existing) {
                amenityResults.push(existing);
              } else {
                const amenity = new Amenity();
                amenity.name = amenityItem.name;
                amenity.key = key;
                amenity.image = amenityItem.icon || iconFallback;
                amenity.type = type;
                amenity.ownerId = 'AIRDATA';
                amenity.createdBy = 'AIRDATA';
                amenity.updatedBy = 'AIRDATA';
                amenitiesToCreate.push(amenity);
                amenityResults.push(amenity);
              }
            });

            if (amenitiesToCreate.length > 0) {
              const savedAmenities: Amenity[] = await queryRunner.manager.save(Amenity, amenitiesToCreate);
              // Update map with new amenities
              savedAmenities.forEach(a => amenityMap.set(a.key, a));
            }

            return amenityResults;
          };

          // Process hotel files and amenities
          const files: File[] = createFiles(item?.images || [], item?.thumbnail?.origin ?? '', item?.name);
          const newFiles: File[] = await queryRunner.manager.save(File, files);

          const groupAmenities: MyTourAmenity[] = item?.groupAmenities?.flatMap(ga => ga.amenities) || [];
          const amenities: Amenity[] = await getOrCreateAmenities(groupAmenities, AmenityType.HOTEL);

          // Create hotel directly with queryRunner.manager
          const newHotel = queryRunner.manager.create(Hotel, {
            localName: item?.name,
            globalName: item?.name,
            code: `H${item?.id}`,
            type: HotelType.HOTEL,
            address: item?.address?.address,
            area: item?.address?.line1 || '',
            star: item?.rating?.starNumber?.toString() || '',
            serviceScope: ServiceScope.LOCAL,
            checkInHouse: item?.checkin?.beginTime,
            checkOutHouse: item?.checkout?.time,
            lat: item?.address?.coordinate?.latitude,
            lng: item?.address?.coordinate?.longitude,
            files: newFiles,
            amenities: amenities,
            source: HotelSource.MYTOUR,
            ownerId: 'AIRDATA',
          });

