  /** Chọn phòng phù hợp với nhu cầu khách dựa trên dữ liệu rate đã gom */
  private assignRooms(
    rateRows: AggregatedRateRow[],
    roomRequests: HotelSearchRoomDto[],
    roomMap: Map<number, HotelSearchRoomInfo>,
  ): HotelPriceRoomSelection[] | null {
    const requests = [...roomRequests].sort((a, b) => this.getGuestCount(b) - this.getGuestCount(a));
    const remaining = rateRows.map(r => ({ ...r }));
    const selection: HotelPriceRoomSelection[] = [];

    for (const request of requests) {
      const guests = this.getGuestCount(request);
      const candidate = remaining.filter(r => r.maxCapacity >= guests).sort((a, b) => a.baseTotal - b.baseTotal);
      if (!candidate.length) return null;
      const chosen = candidate[0];
      const hasAllotment = chosen.minAllotment > 0;
      chosen.minAllotment = Math.max(chosen.minAllotment - 1, 0);
      selection.push({
        roomId: chosen.roomId,
        baseTotal: chosen.baseTotal,
        guestCount: guests,
        guestDetail: {
          adults: request.adults,
          children: request.children.length || 0,
        },
        hasAllotment,
        room: roomMap.get(chosen.roomId),
        priceSettingId: chosen.priceSettingId ?? undefined,
        mealPlan: chosen.mealPlan ?? undefined,
        source: chosen.source ?? undefined,
        condition: chosen.condition ?? undefined,
        cancellationPeriod: chosen.cancellationPeriod ?? undefined,
        cancellationPeriodUnitTime: chosen.cancellationPeriodUnitTime ?? undefined,
        unitType: chosen.unitType ?? undefined,
        amount: chosen.amount ?? undefined,
        dayType: chosen.dayType ?? undefined,
        stayDates: chosen.stayDates ?? undefined,
      });
    }
    return selection;
  }

  /** Tạo danh sách option giá cho từng yêu cầu phòng */
  private buildRoomOptions(
    rateRows: AggregatedRateRow[],
    roomRequests: HotelSearchRoomDto[],
    roomMap: Map<number, HotelSearchRoomInfo>,
  ): HotelPriceOption[] {
    const options: HotelPriceOption[] = [];
    roomRequests.forEach(request => {
      const guests = this.getGuestCount(request);
      const candidates = rateRows.filter(r => r.maxCapacity >= guests);
      const groupedByRoomAndMealPlan = new Map<string, AggregatedRateRow[]>();
      candidates.forEach(candidate => {
        const mealPlanKey = candidate.mealPlan ?? '__NO_MEAL_PLAN__';
        const groupKey = `${candidate.roomId}__${mealPlanKey}`;
        const group = groupedByRoomAndMealPlan.get(groupKey) ?? [];
        group.push(candidate);
        groupedByRoomAndMealPlan.set(groupKey, group);
      });

      const groupedEntries = Array.from(groupedByRoomAndMealPlan.values())
        .map(group => {
          const sortedGroup = [...group].sort((a, b) => a.baseTotal - b.baseTotal);
          const primary = sortedGroup[0];
          const cancellationOptions = sortedGroup.map(item => ({
            priceSettingId: item.priceSettingId ?? undefined,
            baseTotal: item.baseTotal,
            condition: item.condition ?? undefined,
            cancellationPeriod: item.cancellationPeriod ?? undefined,
            cancellationPeriodUnitTime: item.cancellationPeriodUnitTime ?? undefined,
            unitType: item.unitType ?? undefined,
            amount: item.amount ?? undefined,
            hasAllotment: item.minAllotment > 0,
            source: item.source ?? undefined,
            dayType: item.dayType ?? undefined,
            stayDates: item.stayDates ?? undefined,
          }));
          return { primary, cancellationOptions };
        })
        .sort((a, b) => a.primary.baseTotal - b.primary.baseTotal);

      groupedEntries.forEach(({ primary, cancellationOptions }) => {
        options.push({
          id: v4(),
          roomId: primary.roomId,
          baseTotal: primary.baseTotal,
          maxCapacity: primary.maxCapacity,
          maxAdults: primary.maxAdults,
          maxChildren: primary.maxChildren,
          guestCount: guests,
          guestDetail: {
            adults: request.adults,
            children: request.children?.length || 0,
          },
          hasAllotment: primary.minAllotment > 0,
          priceSettingId: primary.priceSettingId ?? undefined,
          mealPlan: primary.mealPlan ?? undefined,
          source: primary.source ?? undefined,
          condition: primary.condition ?? undefined,
          cancellationPeriod: primary.cancellationPeriod ?? undefined,
          cancellationPeriodUnitTime: primary.cancellationPeriodUnitTime ?? undefined,
          unitType: primary.unitType ?? undefined,
          amount: primary.amount ?? undefined,
          dayType: primary.dayType ?? undefined,
          stayDates: primary.stayDates ?? undefined,
          cancellations: cancellationOptions,
        });
      });
    });
    return options;
  }

  /**
   * Group các options theo phòng.
   * Mỗi option đã có promotion được áp dụng (appliedPromotions, discountTotal, netTotal)
   */
  private groupOptionsByRoom(
    options: HotelPriceOption[],
    roomMap: Map<number, HotelSearchRoomInfo>,
  ): HotelPriceOptionGroup[] {
    const grouped = new Map<number, HotelPriceOption[]>();
    options.forEach(option => {
      const list = grouped.get(option.roomId);
      if (list) {
        list.push(option);
      } else {
        grouped.set(option.roomId, [option]);
      }
    });

    return Array.from(grouped.entries()).map(([roomId, roomOptions]) => ({
      room: roomMap.get(roomId),
      // Sort theo netTotal (giá sau giảm) nếu có, không thì dùng baseTotal
      options: roomOptions.sort((a, b) => (a.netTotal ?? a.baseTotal) - (b.netTotal ?? b.baseTotal)),
    }));
  }

  /** Chuẩn bị map thông tin phòng (chi tiết hiển thị) từ danh sách rate */
  private async buildRoomMap(aggregatedRates: AggregatedRateRow[]): Promise<Map<number, HotelSearchRoomInfo>> {
    const roomIds = Array.from(new Set(aggregatedRates.map(r => r.roomId)));
    const basics = await this.roomRepo.findBasicsWithFiles(roomIds);
    const map = new Map<number, HotelSearchRoomInfo>();
    basics.forEach(r => {
      map.set(r.id, {
        id: r.id,
        code: r.code,
        localName: r.localName,
        globalName: r.globalName,
        maxCapacity: r.maxCapacity,
        maxAdults: r.maxAdults,
        maxChildren: r.maxChildren,
        area: r.area ?? undefined,
        bedType: r.bedType ?? undefined,
        isBreakfastIncluded: r.isBreakfastIncluded,
        files: r.files ?? [],
      });
    });
    return map;
  }

  /** Chuẩn hóa danh sách phòng nhập vào để sử dụng làm cache key */
  private normalizeRooms(rooms: HotelSearchRoomDto[]) {
    return [...rooms]
      .map(r => ({
        adults: r.adults,
        children: (r.children || []).map(c => c.age).sort(),
      }))
      .sort((a, b) => b.adults + b.children.length - (a.adults + a.children.length));
  }

  /** Tạo searchId duy nhất dựa trên tham số tìm kiếm để cache kết quả */
  private buildSearchId(
    destinationId: number | undefined,
    hotelId: number | undefined,
    checkIn: dayjs.Dayjs,
    checkOut: dayjs.Dayjs,
    rooms: { adults: number; children: number[] }[],
  ) {
    const payload = {
      destinationId: destinationId || null,
      hotelId: hotelId || null,
      checkIn: checkIn.format('YYYY-MM-DD'),
      checkOut: checkOut.format('YYYY-MM-DD'),
      rooms,
    };
    const hash = createHash('sha1').update(JSON.stringify(payload)).digest('hex');
    return hash;
  }

  /** Cắt danh sách kết quả theo trang và trả về cursor kế tiếp */
  private sliceResults(items: HotelPriceSearchItem[], page: number, size: number) {
    const start = (page - 1) * size;
    const pagedItems = items.slice(start, start + size);
    const nextCursor = start + size < items.length ? start + size : undefined;
    return { items: pagedItems, nextCursor };
  }

  /** Đọc cache kết quả tìm kiếm theo searchId nếu tồn tại */
  private async readCache(searchId: string): Promise<{ items: HotelPriceSearchItem[]; total: number } | null> {
    if (!this.cache) return null;
    const key = `hotel_search:${searchId}`;
    const cached = await this.cache.get(key);
    if (!cached) return null;
    try {
      return JSON.parse(cached);
    } catch {
      return null;
    }
  }

